Here's how to write modern MSTest tests for your `DataFetcher`:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private readonly TestContext _testContext;

    public DataFetcherTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_SuccessResponse_ReturnsContent()
    {
        // Arrange
        var handler = new FakeHttpMessageHandler("hello world", HttpStatusCode.OK);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        // Act
        var result = await fetcher.FetchAsync(
            "https://example.com", _testContext.CancellationToken);

        // Assert
        Assert.AreEqual("hello world", result);
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_NotFound_ThrowsHttpRequestException()
    {
        // Arrange
        var handler = new FakeHttpMessageHandler("", HttpStatusCode.NotFound);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        // Act & Assert
        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await fetcher.FetchAsync(
                "https://example.com", _testContext.CancellationToken));
    }

    [TestMethod]
    [Timeout(3000)]
    public async Task FetchAsync_CancellationRequested_ThrowsOperationCanceledException()
    {
        // Arrange
        var handler = new FakeHttpMessageHandler("data", HttpStatusCode.OK, delay: TimeSpan.FromSeconds(10));
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);
        using var cts = new CancellationTokenSource();
        cts.Cancel(); // cancel immediately

        // Act & Assert
        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com", cts.Token));
    }

    // Minimal fake handler to avoid external HTTP calls
    private sealed class FakeHttpMessageHandler(
        string content, HttpStatusCode statusCode, TimeSpan delay = default)
        : HttpMessageHandler
    {
        protected override async Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            if (delay > TimeSpan.Zero)
            {
                await Task.Delay(delay, cancellationToken);
            }

            return new HttpResponseMessage(statusCode)
            {
                Content = new StringContent(content),
            };
        }
    }
}
```

**Key patterns used:**

- **`[Timeout(ms)]`** — prevents tests from hanging indefinitely; MSTest cancels the token when time expires
- **`TestContext.CancellationToken`** — injected via constructor (MSTest 3.6+), wired to `[Timeout]` so the test is cancelled cooperatively
- **`Assert.ThrowsExactlyAsync<T>`** — validates async exceptions inline instead of the legacy `[ExpectedException]`
- **`sealed` test class** — modern MSTest best practice for performance
- **`FakeHttpMessageHandler`** — avoids real HTTP calls; its `delay` + `cancellationToken` parameter lets you verify cancellation propagation

The cancellation test works by pre-cancelling the token, proving `FetchAsync` correctly forwards the token to `HttpClient.GetAsync`.
